describe('TypeCache', () => {
  let cache: TypeCache;
  let dbPath: string;

  beforeEach(() => {
    dbPath = path.join(os.tmpdir(), `ts-sqlx-test-${Date.now()}.db`);
    cache = new TypeCache(dbPath);
  });

  afterEach(() => {
    cache.close();
    if (fs.existsSync(dbPath)) fs.unlinkSync(dbPath);
