    cache.clear();
    expect(cache.get('SELECT 1')).toBeUndefined();
  });

  it('returns cache stats', () => {
    cache.set('SELECT 1', { params: [], columns: [] });
    cache.set('SELECT 2', { params: [], columns: [] });
    const stats = cache.stats();
    expect(stats.entries).toBe(2);
