  // Date/Time
  date: 'Date',
  timestamp: 'Date',
  timestamptz: 'Date',
  time: 'string',
  timetz: 'string',
  interval: 'string',
  // JSON
  json: 'unknown',
  jsonb: 'unknown',
  // Binary
  bytea: 'Buffer',
  // UUID
  uuid: 'string',
  // Network
  inet: 'string',
  cidr: 'string',
  macaddr: 'string',
  // Full-text search
  tsvector: 'string',
  tsquery: 'string',
  // Geometric
  point: 'string',
  // Bit
  bit: 'string',
  varbit: 'string',
};

export function tsTypeFromPgType(pgType: string): string {
  return PG_TO_TS[pgType] ?? 'unknown';
}
